export const getConfirmImageUrl = (productId: string) => {
  return `/api/v1/student/products/${productId}/images/confirm`;
};

/**
 * Reads the first 64 bytes from S3 and verifies the file's magic bytes match the declared MIME type. Mismatched files are deleted from S3.
 * @summary Step 2/2 — confirm a successful S3 upload
 */
export const confirmImage = async (
  productId: string,
  confirmImageRequest: ConfirmImageRequest,
  options?: RequestInit,
): Promise<void> => {
  return customFetch<void>(getConfirmImageUrl(productId), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(confirmImageRequest),
  });
};

export const getConfirmImageQueryKey = (
  productId: string,
  confirmImageRequest?: ConfirmImageRequest,
) => {
  return [
    "POST",
    `/api/v1/student/products/${productId}/images/confirm`,
    confirmImageRequest,
  ] as const;
};

export const getConfirmImageQueryOptions = <
  TData = Awaited<ReturnType<typeof confirmImage>>,
  TError = ProblemDetail | void,
>(
  productId: string,
  confirmImageRequest: ConfirmImageRequest,
  options?: {
    query?: Partial<UseQueryOptions<Awaited<ReturnType<typeof confirmImage>>, TError, TData>>;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getConfirmImageQueryKey(productId, confirmImageRequest);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof confirmImage>>> = ({ signal }) =>
    confirmImage(productId, confirmImageRequest, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: productId !== null && productId !== undefined,
    staleTime: 60000,
    ...queryOptions,
  } as UseQueryOptions<Awaited<ReturnType<typeof confirmImage>>, TError, TData> & {
    queryKey: DataTag<QueryKey, TData, TError>;
  };
};

